export type OrganizerItem = {
    id: string;
    x: number;
    y: number;
    w: number;
    h: number;
    [key: string]: any;
};
export type OrganizerItemRendered = OrganizerItem & {
    _lane: number;
    _laneCount: number;
    _renderLeft: string;
    _renderWidth: string;
    _renderTop?: string;
    _renderHeight?: string;
};
export type OverlapStrategy = 'compress' | 'expand' | 'calendar' | 'calendar-v';
export type BlockedRegion = {
    x: number;
    y: number;
    w: number;
    h: number;
};
export type GhostState = {
    left: string;
    width: string;
    top: number;
    height: number;
};
